import React from "react";

const Filters = ({ yearRange, setYearRange, widthRange, setWidthRange, heightRange, setHeightRange, filterData }) => {
    const handleRangeChange = (e, rangeType, setRange) => {
        const { value, name } = e.target;
        setRange(prev => (name === "min" ? [parseInt(value), prev[1]] : [prev[0], parseInt(value)]));
    };

    return (
        <aside className="filters">
            <h2>Filters</h2>
            <div className="filter-section">
                <label>Year Range:</label>
                <input
                    type="range"
                    name="min"
                    min="2011"
                    max="2025"
                    value={yearRange[0]}
                    onChange={e => handleRangeChange(e, "year", setYearRange)}
                />
                <input
                    type="range"
                    name="max"
                    min="2011"
                    max="2025"
                    value={yearRange[1]}
                    onChange={e => handleRangeChange(e, "year", setYearRange)}
                />
                <span>{yearRange[0]} - {yearRange[1]}</span>
            </div>
            <div className="filter-section">
                <label>Width:</label>
                <input
                    type="range"
                    name="min"
                    min="0"
                    max="100"
                    value={widthRange[0]}
                    onChange={e => handleRangeChange(e, "width", setWidthRange)}
                />
                <input
                    type="range"
                    name="max"
                    min="0"
                    max="100"
                    value={widthRange[1]}
                    onChange={e => handleRangeChange(e, "width", setWidthRange)}
                />
                <span>{widthRange[0]} - {widthRange[1]}</span>
            </div>
            <div className="filter-section">
                <label>Height:</label>
                <input
                    type="range"
                    name="min"
                    min="0"
                    max="100"
                    value={heightRange[0]}
                    onChange={e => handleRangeChange(e, "height", setHeightRange)}
                />
                <input
                    type="range"
                    name="max"
                    min="0"
                    max="100"
                    value={heightRange[1]}
                    onChange={e => handleRangeChange(e, "height", setHeightRange)}
                />
                <span>{heightRange[0]} - {heightRange[1]}</span>
            </div>
        </aside>
    );
};

export default Filters;
